// // This module inverts the FlagC when bool0 is true, and performs XOR on FlagN and FlagV when bool0 is false.
module top_module(
    input FlagN,
    input FlagV,
    input FlagC,
    input bool0,
    output comparison
    );assign comparison = (bool0) ? (~FlagC) :
                        (~bool0) ? (FlagN ^ FlagV) : 1'bx;

endmodule
